changeSet.sql:

DROP TRIGGER IF EXISTS trg_hl7_create_patient ON patients;

CREATE TRIGGER trg_hl7_create_patient
  AFTER INSERT ON patients
  FOR EACH ROW
  EXECUTE FUNCTION notify_hl7_patient_event();


DROP TRIGGER IF EXISTS trg_hl7_update_patient ON patients;

CREATE TRIGGER trg_hl7_update_patient
  AFTER UPDATE ON patients
  FOR EACH ROW
  EXECUTE FUNCTION notify_hl7_patient_event();

rollback.sql:

DROP TRIGGER IF EXISTS trg_hl7_create_patient ON patients;
DROP TRIGGER IF EXISTS trg_hl7_update_patient ON patients;
DROP FUNCTION IF EXISTS notify_hl7_patient_event();
